public String[] fizzBuzz(int start, int end)
{
    String[] array = new String[end - start];

    for (int i = start; i < end; i++) 
    {
        if (i % 15 == 0) 
        {
            array[i - start] = "FizzBuzz";
        } 
        else if (i % 3 == 0) 
        {
            array[i - start] = "Fizz";
        } 
        else if (i % 5 == 0) 
        {
            array[i - start] = "Buzz";
        } 
        else 
        {
            array[i - start] = String.valueOf(i);
        }
    }

    return array;
}

public boolean evenlySpaced(int a, int b, int c)
{
    int evenlySpaced;

    if (a > b)
    {
     	evenlySpaced = a;
        a = b;
        b = evenlySpaced;
    }

    else if (b > c)
    {
     	evenlySpaced = b;
        b = c;
        c = evenlySpaced;
    }

    return b - a == c - b;
}

