public int[] seriesUp(int n)
{
    int length = n * (n + 1) / 2;
    int[] newArray = new int[length];
    int counter = 0;
    for (int i = 0; i < length; i++)
    {
        counter = i;
		for (int j = 1; j <= i + 1; j++)
        {
            newArray[counter] = j;
            counter++;
        }
        i = i + counter;
    }
    return newArray;
}

