public boolean endOther(String a, String b)
{
	a = a.toLowerCase();
	b = b.toLowerCase();

    int aSize = a.length();
	int bSize = b.length();

	String within;
	String shorter = "";

	if(aSize >= bSize)
	{
		within = a.substring(aSize - bSize);
		shorter = b;
	}
	else
	{
		within = b.substring(bSize - aSize);
		shorter = a;
	}
	return (within.equals(shorter));
}

